class Solution:
    def strWithout3a3b(self, a: int, b: int) -> str:
        result = []
        remaining_a, remaining_b = a, b

        while remaining_a > 0 or remaining_b > 0:
            if len(result) >= 2:
                last_two = result[-2:]
            else:
                last_two = result[:]

            if last_two == ['a', 'a']:
                if remaining_b > 0:
                    result.append('b')
                    remaining_b -= 1
                else:
                    result.append('a')
                    remaining_a -= 1
            elif last_two == ['b', 'b']:
                if remaining_a > 0:
                    result.append('a')
                    remaining_a -= 1
                else:
                    result.append('b')
                    remaining_b -= 1
            else:
                if remaining_a > remaining_b:
                    result.append('a')
                    remaining_a -= 1
                else:
                    result.append('b')
                    remaining_b -= 1

        return ''.join(result)

